class ExamRoom {
public:
    ExamRoom(int n) {
        seats[0] = n;
        for (int i = 1; i < n; i++) {
            seats[i] = i;
        }
    }

    int seat() {
        int closest = INT_MAX;
        for (int i = 0; i < n; i++) {
            if (seats[i] - closest > 1) {
                closest = seats[i];
            }
        }
        return closest;
    }

    void leave(int p) {
        seats[p] = -1;
    }
};
```

